// // This module implements a 4-to-1 multiplexer with an enable signal. When the enable (EN) signal is deasserted, the module selects between four possible outputs based on the 2-bit selector (SEL): if SEL is 00, output B; if SEL is 01, output A; if SEL is 10 or 11, output a HIGH signal (1s). When the enable signal is asserted, the output is consistently a HIGH signal regardless of the selector input.
module top_module(MO, A, B, SEL, EN);input [3:0] A, B;
   input [1:0] SEL;
   input EN;
   output reg [3:0] MO;

   always @ (EN or SEL or A or B) begin
      if (EN) begin
         case (SEL)
            2'b00: MO <= A;
            2'b01: MO <= B;
            2'b10: MO <= 4'b0000;
            2'b11: MO <= 4'b0000;
         endcase
      end else begin
         MO <= 4'b0000;
      end
   end
endmodule
